import { Injectable } from '@angular/core';
import { AXIconResolver } from '@acorex/core/icon';

@Injectable()
export class AppIconResolver implements AXIconResolver {
  private readonly icons: Record<string, string> = {
    home: '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path d="M10 20v-6h4v6h5v-8h3L12 3 2 12h3v8z"/></svg>',
    image: '/assets/icons/logo.svg',
  };

  async resolve(icon: string): Promise<string | null> {
    return this.icons[icon] ?? null;
  }
}

import { ChangeDetectionStrategy, Component, inject, signal } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';
import { AXIconResolverService } from '@acorex/core/icon';

@Component({
  selector: 'app-icon-demo',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (homeSvg(); as svg) {
      <span [innerHTML]="svg"></span>
    }
  `,
})
export class IconDemoComponent {
  private readonly iconResolver = inject(AXIconResolverService);
  private readonly sanitizer = inject(DomSanitizer);

  readonly homeSvg = signal<SafeHtml | null>(null);

  async ngOnInit() {
    const svg = await this.iconResolver.resolve('home');
    this.homeSvg.set(this.sanitizer.bypassSecurityTrustHtml(svg));
  }
}

import { HttpClient } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { firstValueFrom } from 'rxjs';
import { AXIconResolver } from '@acorex/core/icon';

@Injectable()
export class HttpIconResolver implements AXIconResolver {
  private http = inject(HttpClient);

  async resolve(icon: string): Promise<string | null> {
    // Only handle keys prefixed with 'asset:'
    if (!icon.startsWith('asset:')) {
      return null;
    }

    const path = icon.replace('asset:', '');
    try {
      return await firstValueFrom(this.http.get(path, { responseType: 'text' }));
    } catch {
      return null;
    }
  }
}

