import { ApplicationConfig } from '@angular/core';
import { AX_ICON_RESOLVER, AXIconResolverDefault } from '@acorex/core/icon';
import { MapIconResolver } from './map-icon.resolver';
import { UiIconResolver } from './ui-icon.resolver';

export const appConfig: ApplicationConfig = {
  providers: [
    // Tried first — handles map-* keys
    { provide: AX_ICON_RESOLVER, useClass: MapIconResolver, multi: true },
    // Tried second — handles ui-* keys
    { provide: AX_ICON_RESOLVER, useClass: UiIconResolver, multi: true },
    // Last resort — returns the key unchanged
    { provide: AX_ICON_RESOLVER, useClass: AXIconResolverDefault, multi: true },
  ],
};

import { Injectable } from '@angular/core';
import { AXIconResolver } from '@acorex/core/icon';

@Injectable()
export class MapIconResolver implements AXIconResolver {
  private iconMap: Record<string, string> = {
    'map-cloud': '<svg xmlns="http://www.w3.org/2000/svg" width="25" height="25" viewBox="0 0 640 512">...</svg>',
    'map-sun': '<svg xmlns="http://www.w3.org/2000/svg" width="25" height="25" viewBox="0 0 512 512">...</svg>',
    image: 'https://picsum.photos/200',
  };

  async resolve(icon: string): Promise<string | null> {
    return this.iconMap[icon] ?? null;
  }
}

import { Injectable } from '@angular/core';
import { AXPoiMarker, AXPoiProvider } from '@acorex/components/map';

@Injectable()
export class WeatherPoiProvider implements AXPoiProvider {
  get key() {
    return 'weather';
  }

  async provide(): Promise<AXPoiMarker[]> {
    return [
      {
        latitude: 35.6895,
        longitude: 139.6917,
        title: 'Tokyo Weather',
        iconKey: 'map-sun', // resolved by AXIconResolverService inside AXLeafletService
        popup: '<strong>Tokyo</strong><br>Sunny, 28°C',
      },
    ];
  }
}

import { inject } from '@angular/core';
import { AXIconResolverService } from '@acorex/core/icon';

const iconService = inject(AXIconResolverService);

async function loadIcon(key: string) {
  try {
    return await iconService.resolve(key);
  } catch (error) {
    // Thrown when no resolver returns a non-null value:
    // Error: AXIconResolverService: Could not resolve icon "unknown-key"
    console.warn('Icon not found, using fallback');
    return null;
  }
}

import { Routes } from '@angular/router';
import { AX_ICON_RESOLVER, AXIconResolverService } from '@acorex/core/icon';
import { MapIconResolver } from './map-icon.resolver';

export const mapFeatureRoutes: Routes = [
  {
    path: '',
    providers: [
      AXIconResolverService,
      {
        provide: AX_ICON_RESOLVER,
        useClass: MapIconResolver,
        multi: true,
      },
    ],
    loadComponent: () => import('./map-page.component').then((m) => m.MapPageComponent),
  },
];
